#include <bits/stdc++.h>
using namespace std;

const long long INF = 1e18;

int main() {
    int n, m; cin >> n >> m;
    vector<vector<pair<int,int>>> adj(n + 1); // {neighbor, weight}

    for (int i = 0; i < m; i++) {
        int u, v, w; cin >> u >> v >> w;
        adj[u].push_back({v, w});
        adj[v].push_back({u, w}); // remove for directed
    }

    int src; cin >> src;
    vector<long long> dist(n + 1, INF);
    priority_queue<pair<long long,int>,
                   vector<pair<long long,int>>,
                   greater<>> pq; // min-heap: {dist, node}

    dist[src] = 0;
    pq.push({0, src});

    while (!pq.empty()) {
        auto [d, u] = pq.top(); pq.pop();

        if (d > dist[u]) continue; // stale entry — skip!

        for (auto [v, w] : adj[u]) {
            if (dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
                pq.push({dist[v], v});
            }
        }
    }

    for (int i = 1; i <= n; i++) {
        if (dist[i] == INF) cout << -1;
        else cout << dist[i];
        cout << "\n";
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const long long INF = 1e18;

struct Edge { int u, v, w; };

int main() {
    int n, m; cin >> n >> m;
    vector<Edge> edges(m);
    for (auto& [u, v, w] : edges) cin >> u >> v >> w;

    int src; cin >> src;
    vector<long long> dist(n + 1, INF);
    dist[src] = 0;

    // Relax all edges V-1 times
    for (int iter = 0; iter < n - 1; iter++) {
        for (auto& [u, v, w] : edges) {
            if (dist[u] != INF && dist[u] + w < dist[v]) {
                dist[v] = dist[u] + w;
            }
        }
    }

    // Check for negative cycles (Vth relaxation)
    bool neg_cycle = false;
    for (auto& [u, v, w] : edges) {
        if (dist[u] != INF && dist[u] + w < dist[v]) {
            neg_cycle = true;
            break;
        }
    }

    if (neg_cycle) {
        cout << "NEGATIVE CYCLE DETECTED\n";
    } else {
        for (int i = 1; i <= n; i++) {
            cout << (dist[i] == INF ? -1 : dist[i]) << "\n";
        }
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m; cin >> n >> m;
    vector<vector<int>> adj(n + 1);
    vector<int> indegree(n + 1, 0);

    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v; // u -> v (u must come before v)
        adj[u].push_back(v);
        indegree[v]++;
    }

    queue<int> q;
    for (int i = 1; i <= n; i++)
        if (indegree[i] == 0) q.push(i);

    vector<int> topo;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        topo.push_back(u);
        for (int v : adj[u]) {
            indegree[v]--;
            if (indegree[v] == 0) q.push(v);
        }
    }

    if ((int)topo.size() != n) {
        cout << "CYCLE DETECTED — no valid topological order\n";
    } else {
        for (int x : topo) cout << x << " ";
        cout << "\n";
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

vector<vector<int>> adj;
vector<int> color; // 0=white, 1=gray, 2=black
vector<int> topo;
bool has_cycle = false;

void dfs(int u) {
    color[u] = 1; // gray: in stack
    for (int v : adj[u]) {
        if (color[v] == 1) { has_cycle = true; return; } // back edge
        if (color[v] == 0) dfs(v);
    }
    color[u] = 2; // black: done
    topo.push_back(u); // add after all descendants processed
}

int main() {
    int n, m; cin >> n >> m;
    adj.assign(n + 1, {});
    color.assign(n + 1, 0);
    for (int i = 0; i < m; i++) {
        int u, v; cin >> u >> v;
        adj[u].push_back(v);
    }
    for (int i = 1; i <= n; i++)
        if (color[i] == 0) dfs(i);
    if (has_cycle) {
        cout << "CYCLE\n";
    } else {
        reverse(topo.begin(), topo.end()); // reverse post-order = topo order
        for (int x : topo) cout << x << " ";
    }
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

int main() {
    int n, m; cin >> n >> m;
    vector<vector<pair<int,int>>> adj(n + 1); // {neighbor, weight}
    vector<int> indegree(n + 1, 0);

    for (int i = 0; i < m; i++) {
        int u, v, w; cin >> u >> v >> w;
        adj[u].push_back({v, w});
        indegree[v]++;
    }

    // Kahn's to get topo order
    queue<int> q;
    for (int i = 1; i <= n; i++)
        if (indegree[i] == 0) q.push(i);

    vector<long long> dp(n + 1, 0); // dp[u] = longest path ending at u
    while (!q.empty()) {
        int u = q.front(); q.pop();
        for (auto [v, w] : adj[u]) {
            dp[v] = max(dp[v], dp[u] + w);
            if (--indegree[v] == 0) q.push(v);
        }
    }

    cout << *max_element(dp.begin(), dp.end()) << "\n";
    return 0;
}

#include <bits/stdc++.h>
using namespace std;

const long long INF = 1e18;
int dx[] = {0, 0, 1, -1};
int dy[] = {1, -1, 0, 0};

int main() {
    int R, C; cin >> R >> C;
    vector<vector<int>> cost(R, vector<int>(C));
    for (int i = 0; i < R; i++)
        for (int j = 0; j < C; j++) cin >> cost[i][j];

    vector<vector<long long>> dist(R, vector<long long>(C, INF));
    priority_queue<tuple<long long,int,int>,
                   vector<tuple<long long,int,int>>,
                   greater<>> pq;
    dist[0][0] = cost[0][0];
    pq.push({cost[0][0], 0, 0});

    while (!pq.empty()) {
        auto [d, r, c] = pq.top(); pq.pop();
        if (d > dist[r][c]) continue;
        for (int dir = 0; dir < 4; dir++) {
            int nr = r + dx[dir], nc = c + dy[dir];
            if (nr < 0 || nr >= R || nc < 0 || nc >= C) continue;
            long long nd = d + cost[nr][nc];
            if (nd < dist[nr][nc]) {
                dist[nr][nc] = nd;
                pq.push({nd, nr, nc});
            }
        }
    }
    cout << dist[R-1][C-1] << "\n";
    return 0;
}

