// N courses labeled 1..N, and M prerequisites of the form [a, b]
// meaning you must complete course b before course a.
// Print a valid order to take all courses, or "IMPOSSIBLE" if circular dependency.
// Input: N M, then M lines of A B (A requires B first)
// Example:
// 4 3
// 2 1
// 3 2
// 4 2
// Output: 1 2 3 4  (or any valid topological order)

sections.solution:
#include <bits/stdc++.h>
using namespace std;

int main() {
    ios_base::sync_with_stdio(false);
    cin.tie(NULL);

    int n, m; cin >> n >> m;
    vector<vector<int>> adj(n + 1);
    vector<int> indegree(n + 1, 0);

    for (int i = 0; i < m; i++) {
        int a, b; cin >> a >> b;
        // b must come before a, so edge b -> a
        adj[b].push_back(a);
        indegree[a]++;
    }

    queue<int> q;
    for (int i = 1; i <= n; i++)
        if (indegree[i] == 0) q.push(i);

    vector<int> order;
    while (!q.empty()) {
        int u = q.front(); q.pop();
        order.push_back(u);
        for (int v : adj[u])
            if (--indegree[v] == 0) q.push(v);
    }

    if ((int)order.size() != n) {
        cout << "IMPOSSIBLE\n";
    } else {
        for (int i = 0; i < n; i++)
            cout << order[i] << " \n"[i == n-1];
    }
    return 0;
}
